import { cookies, headers, draftMode } from 'next/headers'
import { connection } from 'next/server'

export async function CachedCookiesReader() {
  'use cache'

  try {
    await cookies()
  } catch {}

  return null
}

export async function CachedHeadersReader() {
  'use cache'

  try {
    await headers()
  } catch {}

  return null
}

export async function CachedDraftModeEnabler() {
  'use cache'

  try {
    ;(await draftMode()).enable()
  } catch {}

  return null
}

export async function CachedConnectionCaller() {
  'use cache'

  try {
    await connection()
  } catch {}

  return null
}
